import FloatingLabel from 'react-bootstrap/FloatingLabel';
import Form from 'react-bootstrap/Form';

function FormFloatingTextareaExample() {
  return (
    <>
      <FloatingLabel
        controlId="floatingTextarea" label="Full Name" xs={6} className=" mb-3 form-floating"
      >
        <Form.Control as="textarea" placeholder="Enter your full name" />
      </FloatingLabel>
      <FloatingLabel controlId="floatingTextarea2" label="Email">
        <Form.Control
          as="textarea" placeholder="Enter your email" style={{ height: '100px' }}
        />
      </FloatingLabel>
    </>
  );
}

export default FormFloatingTextareaExample;
